<script setup lang="ts">
import { computed, onMounted, reactive, ref, watch } from "vue";
import { ElMessage, ElMessageBox } from "element-plus";
import { api, type ApplicationItem, type BillingSummary, type PlatformUser, type QuotaBalance, type TeamEntitlement, type TeamMemberItem, type TeamSummary } from "../api";

const props = defineProps<{ ownerUserId?: number | null; ownerMemberId?: number | null; adminMode: boolean }>();
const teams = ref<TeamSummary[]>([]); const total = ref(0); const selectedId = ref<number | null>(null); const members = ref<TeamMemberItem[]>([]); const apps = ref<ApplicationItem[]>([]); const grantedModels = ref<string[]>([]); const allModels = ref<string[]>([]); const users = ref<PlatformUser[]>([]); const requests = ref<TeamEntitlement[]>([]); const teamQuota = ref<QuotaBalance | null>(null); const teamBilling = ref<BillingSummary | null>(null); const memberQuota = ref<Record<number, QuotaBalance>>({}); const loading = ref(false); const dialog = ref<"team" | "owner" | "request" | "member" | "application" | "access" | null>(null); const revealed = ref("");
const filters = reactive({ keyword: "", enabled: "", logicalModel: "", page: 0, size: 10 }); const selected = computed(() => teams.value.find(team => team.teamId === selectedId.value) ?? null);
const teamForm = reactive({ organizationId: 1, name: "", ownerUserId: null as number | null, keyRpm: 60, teamRpm: 600, teamConcurrency: 20, modelConcurrency: 50 }); const ownerForm = ref<number | null>(null); const requestForm = reactive({ modelNames: [] as string[], requestedTokens: 100000, purpose: "", expiresAt: "" }); const memberUserId = ref<number | null>(null); const appForm = reactive({ name: "" }); const accessForm = reactive({ memberId: 0, applicationId: 0, modelNames: [] as string[], tokenAllocation: 10000, reason: "" });
const unassignedUsers = computed(() => users.value.filter(user => user.enabled && !user.teamId));

async function load(reset = false) { if (reset) filters.page = 0; loading.value = true; try { const [teamData, modelData, userData] = await Promise.all([api.teams({ ...filters, enabled: filters.enabled || null, ownerUserId: props.ownerUserId ?? null }), api.directModels(), api.users()]); teams.value = teamData.items; total.value = teamData.total; allModels.value = modelData.items.filter(item => item.enabled).map(item => item.modelName); users.value = userData.items; const preferredId = teams.value.some(team => team.teamId === selectedId.value) ? selectedId.value : teams.value[0]?.teamId; if (preferredId) await select(preferredId); else clearDetail(); } catch (error) { ElMessage.error(error instanceof Error ? error.message : "团队列表加载失败"); } finally { loading.value = false; } }
function clearDetail() { selectedId.value = null; members.value = []; apps.value = []; grantedModels.value = []; requests.value = []; teamQuota.value = null; teamBilling.value = null; memberQuota.value = {}; }
function clear() { Object.assign(filters, { keyword: "", enabled: "", logicalModel: "", page: 0 }); void load(); }
async function select(id: number) { selectedId.value = id; try { const [memberData, appData, access, requestData, quota, billing] = await Promise.all([api.members(id), api.applications(id), api.teamModels(id), api.teamEntitlementRequests(id), api.teamQuota(id), api.teamBillingSummary(id)]); members.value = memberData.items; apps.value = appData.items; grantedModels.value = access.logicalModels; requests.value = requestData.items; teamQuota.value = quota; teamBilling.value = billing; const balances = await Promise.all(memberData.items.map(async member => [member.memberId, await api.memberQuota(member.memberId)] as const)); memberQuota.value = Object.fromEntries(balances); } catch (error) { ElMessage.error(error instanceof Error ? error.message : "团队详情加载失败"); } }
async function saveTeam() { try { await api.createTeam(teamForm); dialog.value = null; Object.assign(teamForm, { name: "", ownerUserId: null }); await load(); ElMessage.success("团队已创建"); } catch (error) { ElMessage.error(error instanceof Error ? error.message : "创建失败"); } }
function openOwner() { ownerForm.value = selected.value?.ownerMemberId ? users.value.find(user => user.memberId === selected.value?.ownerMemberId)?.userId ?? null : null; dialog.value = "owner"; }
async function saveOwner() { if (!selected.value) return; try { await api.setTeamOwner(selected.value.teamId, ownerForm.value); dialog.value = null; await load(); ElMessage.success(ownerForm.value ? "负责人已设置" : "负责人已清空，团队已回到草稿状态"); } catch (error) { ElMessage.error(error instanceof Error ? error.message : "负责人更新失败"); } }
async function submitRequest() { if (!selected.value || !props.ownerMemberId) return; try { await api.requestTeamEntitlement(selected.value.teamId, { ownerMemberId: props.ownerMemberId, ...requestForm, expiresAt: requestForm.expiresAt || null }); dialog.value = null; await select(selected.value.teamId); ElMessage.success("团队授权申请已提交"); } catch (error) { ElMessage.error(error instanceof Error ? error.message : "申请提交失败"); } }
async function review(request: TeamEntitlement, decision: "APPROVE" | "REJECT") { try { if (decision === "REJECT") await ElMessageBox.confirm("驳回后负责人可重新提交申请。", "确认驳回", { type: "warning" }); await api.reviewTeamEntitlement(request.requestId, decision); await select(request.teamId); await load(); ElMessage.success(decision === "APPROVE" ? "团队授权已批准" : "申请已驳回"); } catch (error) { if (error !== "cancel" && error !== "close") ElMessage.error(error instanceof Error ? error.message : "审批失败"); } }
async function addMember() { if (!selected.value || !props.ownerMemberId || !memberUserId.value) return; try { await api.addExistingMember(selected.value.teamId, props.ownerMemberId, memberUserId.value); dialog.value = null; memberUserId.value = null; await select(selected.value.teamId); await load(); ElMessage.success("成员已加入团队"); } catch (error) { ElMessage.error(error instanceof Error ? error.message : "添加成员失败"); } }
async function saveApplication() { if (!selected.value) return; try { await api.createApplication(selected.value.teamId, appForm); dialog.value = null; appForm.name = ""; await select(selected.value.teamId); } catch (error) { ElMessage.error(error instanceof Error ? error.message : "创建应用失败"); } }
function openAccess(memberId: number) { accessForm.memberId = memberId; accessForm.applicationId = apps.value[0]?.applicationId ?? 0; accessForm.modelNames = [...grantedModels.value]; accessForm.tokenAllocation = 10000; accessForm.reason = ""; dialog.value = "access"; }
async function saveAccess() { if (!selected.value || !props.ownerMemberId) return; try { const result = await api.grantMemberAccess(selected.value.teamId, accessForm.memberId, { ownerMemberId: props.ownerMemberId, applicationId: accessForm.applicationId, modelNames: accessForm.modelNames, tokenAllocation: accessForm.tokenAllocation, reason: accessForm.reason }); dialog.value = null; if (result.apiKey) { revealed.value = result.apiKey; ElMessageBox.alert(`<p>系统已为成员生成 Key。请立即安全交付，关闭后不可恢复。</p><code>${result.apiKey}</code>`, "成员 Key 已生成", { dangerouslyUseHTMLString: true, confirmButtonText: "我已记录" }); } else ElMessage.success("成员访问权限和额度已更新"); await select(selected.value.teamId); } catch (error) { ElMessage.error(error instanceof Error ? error.message : "成员授权失败"); } }
async function removeTeam() { if (!selected.value) return; try { await ElMessageBox.confirm(`删除 ${selected.value.name} 会同时清理成员关系、应用、虚拟 Key、调用、账单和额度数据，且不可恢复。`, "确认删除团队", { type: "warning" }); await api.deleteTeam(selected.value.teamId); clearDetail(); await load(); ElMessage.success("团队已删除"); } catch (error) { if (error !== "cancel" && error !== "close") ElMessage.error(error instanceof Error ? error.message : "删除失败"); } }
watch(() => [props.ownerUserId, props.ownerMemberId, props.adminMode], () => { void load(); }); onMounted(load);
</script>

<template>
  <section class="page-stack" v-loading="loading">
    <header class="page-heading"><div><p class="eyebrow">Delegated entitlement control</p><h1>{{ adminMode ? '企业团队' : '我的团队' }}</h1><p>{{ adminMode ? '管理员审批团队申请；负责人将已获模型和额度分配给成员。' : '申请团队资源、维护成员，并由系统自动签发成员专属 Key。' }}</p></div><el-button v-if="adminMode" type="primary" @click="dialog = 'team'">新增团队</el-button></header>
    <section class="team-master"><aside class="surface team-list"><el-form class="search-stack" @submit.prevent="load(true)"><el-input v-model="filters.keyword" placeholder="搜索团队" clearable/><el-select v-model="filters.enabled" placeholder="状态" clearable><el-option label="启用" value="true"/><el-option label="停用" value="false"/></el-select><el-select v-model="filters.logicalModel" placeholder="已获批模型" clearable><el-option v-for="model in allModels" :key="model" :label="model" :value="model"/></el-select><div><el-button type="primary" native-type="submit">搜索</el-button><el-button @click="clear">重置</el-button></div></el-form><div class="compact-list"><button v-for="team in teams" :key="team.teamId" class="list-row" :class="{ selected: team.teamId === selectedId }" @click="select(team.teamId)"><strong>{{ team.name }}</strong><small>{{ team.status }} · {{ team.memberCount }} 成员 · {{ team.keyCount }} 个 Key</small></button></div><el-pagination v-if="adminMode" small layout="prev, pager, next" :total="total" :page-size="filters.size" :current-page="filters.page + 1" @current-change="page => { filters.page = page - 1; load(); }"/></aside>
      <section v-if="selected" class="surface team-detail"><div class="section-title"><div><p class="eyebrow">Team entitlement boundary</p><h2>{{ selected.name }}</h2><p class="muted">负责人 {{ selected.ownerName || '未指定' }} · {{ selected.ownerEmail || '-' }}</p></div><div><el-tag :type="selected.status === 'ACTIVE' ? 'success' : selected.status === 'DRAFT' ? 'warning' : 'info'">{{ selected.status }}</el-tag><el-button v-if="adminMode" text @click="openOwner">设置负责人</el-button><el-button v-if="adminMode" text type="danger" @click="removeTeam">删除团队</el-button></div></div>
        <div class="detail-metrics"><span>Key RPM<strong>{{ selected.keyRpm }}</strong></span><span>团队 RPM<strong>{{ selected.teamRpm }}</strong></span><span>团队并发<strong>{{ selected.teamConcurrency }}</strong></span><span>模型并发<strong>{{ selected.modelConcurrency }}</strong></span></div>
        <el-alert v-if="selected.status === 'DRAFT'" type="warning" :closable="false" title="草稿团队尚无负责人；管理员不能发放模型权限或团队额度。"/>
        <div class="detail-block"><div class="section-title"><h3>团队模型权限</h3><el-button v-if="!adminMode && props.ownerMemberId" text type="primary" @click="dialog = 'request'">申请模型与额度</el-button></div><el-tag v-for="model in grantedModels" :key="model" class="app-tag">{{ model }}</el-tag><p v-if="!grantedModels.length" class="muted">尚未获批团队模型权限。</p></div>
        <div class="detail-block"><div class="section-title"><h3>公共额度与团队账单</h3><small class="muted">公共额度仅供负责人向成员划拨；实际消费按成员汇总。</small></div><div class="detail-metrics"><span>可分配 Token<strong>{{ teamQuota?.availableTokens ?? 0 }}</strong></span><span>成员冻结<strong>{{ teamQuota?.frozenTokens ?? 0 }}</strong></span><span>团队已消费<strong>{{ teamBilling?.totalTokens ?? 0 }}</strong></span><span>模型成本<strong>{{ teamBilling?.totalAmount ?? 0 }} {{ teamBilling?.currency ?? 'USD' }}</strong></span></div></div>
        <div class="detail-block"><div class="section-title"><h3>团队授权申请</h3><small class="muted">负责人提交，平台管理员审批</small></div><el-table :data="requests" size="small"><el-table-column prop="purpose" label="用途"/><el-table-column label="模型"><template #default="scope">{{ scope.row.modelNames.join('，') }}</template></el-table-column><el-table-column prop="requestedTokens" label="Token"/><el-table-column prop="status" label="状态"/><el-table-column v-if="adminMode" label="操作" width="130"><template #default="scope"><el-button v-if="scope.row.status === 'PENDING'" text type="primary" @click="review(scope.row, 'APPROVE')">批准</el-button><el-button v-if="scope.row.status === 'PENDING'" text type="danger" @click="review(scope.row, 'REJECT')">驳回</el-button></template></el-table-column></el-table></div>
        <div class="detail-block"><div class="section-title"><h3>应用</h3><el-button v-if="!adminMode && props.ownerMemberId" text type="primary" @click="dialog = 'application'">新增应用</el-button></div><el-table :data="apps" size="small"><el-table-column prop="name" label="应用"/><el-table-column prop="createdAt" label="创建时间"/></el-table></div>
        <div class="detail-block"><div class="section-title"><h3>成员与个人授权</h3><el-button v-if="!adminMode && props.ownerMemberId" text type="primary" @click="dialog = 'member'">添加现有用户</el-button></div><el-table :data="members" size="small"><el-table-column prop="name" label="姓名"/><el-table-column prop="email" label="邮箱"/><el-table-column prop="role" label="角色"/><el-table-column label="个人可用 Token"><template #default="scope">{{ memberQuota[scope.row.memberId]?.availableTokens ?? 0 }}</template></el-table-column><el-table-column label="个人已消费"><template #default="scope">{{ memberQuota[scope.row.memberId]?.consumedTokens ?? 0 }}</template></el-table-column><el-table-column v-if="!adminMode" label="操作" width="120"><template #default="scope"><el-button v-if="scope.row.role !== 'OWNER'" text type="primary" @click="openAccess(scope.row.memberId)">分配访问</el-button></template></el-table-column></el-table></div>
      </section><section v-else class="surface empty-state"><h2>{{ adminMode ? '选择一个团队' : '该负责人尚未分配团队' }}</h2><p>从左侧选择团队后继续配置授权。</p></section></section>
    <el-dialog v-model="dialog" :title="dialog === 'team' ? '新增团队' : dialog === 'owner' ? '设置团队负责人' : dialog === 'request' ? '申请团队授权' : dialog === 'member' ? '添加团队成员' : dialog === 'application' ? '新增应用' : '分配成员访问'" width="560px"><el-form v-if="dialog === 'team'" label-position="top"><el-form-item label="团队名称"><el-input v-model="teamForm.name"/></el-form-item><el-form-item label="负责人（可选）"><el-select v-model="teamForm.ownerUserId" clearable filterable placeholder="不选则创建草稿团队"><el-option v-for="user in unassignedUsers" :key="user.userId" :label="`${user.name} · ${user.email}`" :value="user.userId"/></el-select></el-form-item></el-form><el-form v-else-if="dialog === 'owner'" label-position="top"><el-form-item label="负责人"><el-select v-model="ownerForm" clearable filterable placeholder="清空后团队将回到草稿"><el-option v-for="user in unassignedUsers" :key="user.userId" :label="`${user.name} · ${user.email}`" :value="user.userId"/></el-select></el-form-item></el-form><el-form v-else-if="dialog === 'request'" label-position="top"><el-form-item label="所需模型"><el-checkbox-group v-model="requestForm.modelNames" class="checkbox-stack"><el-checkbox v-for="model in allModels" :key="model" :label="model">{{ model }}</el-checkbox></el-checkbox-group></el-form-item><el-form-item label="申请 Token"><el-input-number v-model="requestForm.requestedTokens" :min="1"/></el-form-item><el-form-item label="用途"><el-input v-model="requestForm.purpose" type="textarea"/></el-form-item><el-form-item label="到期时间（可选）"><el-input v-model="requestForm.expiresAt" placeholder="2026-12-31T23:59:59+08:00"/></el-form-item></el-form><el-form v-else-if="dialog === 'member'" label-position="top"><el-form-item label="选择未分配用户"><el-select v-model="memberUserId" filterable><el-option v-for="user in unassignedUsers" :key="user.userId" :label="`${user.name} · ${user.email}`" :value="user.userId"/></el-select></el-form-item></el-form><el-form v-else-if="dialog === 'application'" label-position="top"><el-form-item label="应用名称"><el-input v-model="appForm.name"/></el-form-item></el-form><el-form v-else label-position="top"><el-form-item label="调用应用"><el-select v-model="accessForm.applicationId"><el-option v-for="app in apps" :key="app.applicationId" :label="app.name" :value="app.applicationId"/></el-select></el-form-item><el-form-item label="成员可用模型"><el-checkbox-group v-model="accessForm.modelNames" class="checkbox-stack"><el-checkbox v-for="model in grantedModels" :key="model" :label="model">{{ model }}</el-checkbox></el-checkbox-group></el-form-item><el-form-item label="划拨 Token"><el-input-number v-model="accessForm.tokenAllocation" :min="1"/></el-form-item><el-form-item label="说明"><el-input v-model="accessForm.reason"/></el-form-item></el-form><template #footer><el-button @click="dialog = null">取消</el-button><el-button type="primary" :disabled="dialog === 'team' ? !teamForm.name : dialog === 'request' ? !requestForm.modelNames.length || !requestForm.purpose : dialog === 'member' ? !memberUserId : dialog === 'application' ? !appForm.name : dialog === 'access' ? !accessForm.applicationId || !accessForm.modelNames.length : false" @click="dialog === 'team' ? saveTeam() : dialog === 'owner' ? saveOwner() : dialog === 'request' ? submitRequest() : dialog === 'member' ? addMember() : dialog === 'application' ? saveApplication() : saveAccess()">保存</el-button></template></el-dialog>
  </section>
</template>
